import { useState, useEffect } from 'react';
import { getRequest } from '../services';
import { baseURL } from '../services'; export const useFetchRecipient = (chat, user) => { const [recipientUser, setRecipientUser] = useState(null); useEffect(() => { const fetchRecipient = async () => { const recipientID = chat.members.find((id) => id !== user._id); if (!recipientID) return; const response = await getRequest(`${baseURL}/users/find/${recipientID}`); if (!response.error) { setRecipientUser(response); } }; fetchRecipient(); }, [chat, user]); return recipientUser;
};

