import React, { createContext, useState, useEffect } from 'react';
import jwtDecode from 'jwt-decode'; export const AuthContext = createContext(); const AuthProvider = ({ children }) => { const [user, setUser] = useState(null); useEffect(() => { const token = localStorage.getItem('token'); if (token) { const decoded = jwtDecode(token); setUser({ id: decoded.id }); } }, []); const login = (token) => { localStorage.setItem('token', token); const decoded = jwtDecode(token); setUser({ id: decoded.id }); }; const logout = () => { localStorage.removeItem('token'); setUser(null); }; return ( <AuthContext.Provider value={{ user, login, logout }}> {children} </AuthContext.Provider> );
}; export default AuthProvider; Socket Context: // src/context/SocketContext.js
import React, { createContext, useContext, useEffect, useState } from 'react';
import io from 'socket.io-client';
import { AuthContext } from './AuthContext'; export const SocketContext = createContext(); const SocketProvider = ({ children }) => { const { user } = useContext(AuthContext); const [socket, setSocket] = useState(null); useEffect(() => { if (user) { const newSocket = io('http://localhost:5000'); setSocket(newSocket); newSocket.emit('join', user.id); return () => newSocket.close(); } }, [user]); return ( <SocketContext.Provider value={socket}> {children} </SocketContext.Provider> );
}; export default SocketProvider; App Component: // src/App.js
import React from 'react';
import AuthProvider from './context/AuthContext';
import SocketProvider from './context/SocketContext';
import Chat from './components/Chat';
import Login from './components/Login'; const App = () => { return ( <AuthProvider> <SocketProvider> <div> <Login /> <Chat /> </div> </SocketProvider> </AuthProvider> );
}; export default App; Login Component: // src/components/Login.js
import React, { useState, useContext } from 'react';
import { AuthContext } from '../context/AuthContext'; const Login = () => { const [username, setUsername] = useState(''); const [password, setPassword] = useState(''); const { login } = useContext(AuthContext); const handleSubmit = async (e) => { e.preventDefault(); const res = await fetch('http://localhost:5000/login', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ username, password }), }); const data = await res.json(); login(data.token); }; return ( <form onSubmit={handleSubmit}> <input type="text" placeholder="Username" value={username} onChange={(e) => setUsername(e.target.value)} /> <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} /> <button type="submit">Login</button> </form> );
}; export default Login; Chat Component: // src/components/Chat.js
import React, { useContext, useEffect, useState } from 'react';
import { SocketContext } from '../context/SocketContext';
import { AuthContext } from '../context/AuthContext'; const Chat = () => { const { user } = useContext(AuthContext); const socket = useContext(SocketContext); const [message, setMessage] = useState(''); const [messages, setMessages] = useState([]); useEffect(() => { if (socket) { socket.on('message', (message) => { setMessages((prevMessages) => [...prevMessages, message]); }); } }, [socket]); const sendMessage = () => { if (socket && message) { socket.emit('message', { senderId: user.id, message }); setMessage(''); } }; return ( <div> <div> {messages.map((msg, index) => ( <div key={index}>{msg.message}</div> ))} </div> <input type="text" value={message} onChange={(e) => setMessage(e.target.value)} /> <button onClick={sendMessage}>Send</button> </div> );
}; export default Chat; ## Conclusion In this tutorial, we have created a basic real-time chat application with user authentication and real-time messaging using React, Node.js, and Socket.IO. This project serves as a foundation for more advanced features and optimizations, such as handling more complex user states, implementing message persistence with a database, and enhancing the user interface with additional functionalities. ### Future Enhancements
- **Message Persistence:** Integrate a database (e.g., MongoDB) to store messages.
- **User Profiles:** Allow users to update their profiles and view other users' profiles.
- **Advanced Notifications:** Implement push notifications for messages when the user is offline. By following this guide, you have gained insights into building real-time web applications and can now extend the functionality as needed for your projects.

