// server/controllers/userController.js
const User = require('../models/userModel');
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const validator = require('validator'); const registerUser = async (req, res) => { const { name, email, password } = req.body; if (!name || !email || !password) { return res.status(400).json({ message: 'All fields are required' }); } if (!validator.isEmail(email)) { return res.status(400).json({ message: 'Invalid email format' }); } if (!validator.isStrongPassword(password)) { return res.status(400).json({ message: 'Password must be strong' }); } let user = await User.findOne({ email }); if (user) { return res.status(400).json({ message: 'User with the given email already exists' }); } const salt = await bcrypt.genSalt(10); const hashedPassword = await bcrypt.hash(password, salt); user = new User({ name, email, password: hashedPassword }); await user.save(); const token = jwt.sign({ _id: user._id }, process.env.JWT_SECRET_KEY, { expiresIn: '3d' }); res.status(201).json({ _id: user._id, name: user.name, email: user.email, token });
}; const loginUser = async (req, res) => { const { email, password } = req.body; if (!email || !password) { return res.status(400).json({ message: 'All fields are required' }); } const user = await User.findOne({ email }); if (!user) { return res.status(400).json({ message: 'Invalid email or password' }); } const isValidPassword = await bcrypt.compare(password, user.password); if (!isValidPassword) { return res.status(400).json({ message: 'Invalid email or password' }); } const token = jwt.sign({ _id: user._id }, process.env.JWT_SECRET_KEY, { expiresIn: '3d' }); res.status(200).json({ _id: user._id, name: user.name, email: user.email, token });
}; const getUsers = async (req, res) => { const users = await User.find(); res.status(200).json(users);
}; const getUser = async (req, res) => { const user = await User.findById(req.params.userId); if (!user) { return res.status(404).json({ message: 'User not found' }); } res.status(200).json(user);
}; module.exports = { registerUser, loginUser, getUsers, getUser };

